+"use client";
+
+import { add } from "@workspace/lib";
+import { useId, useState } from "react";
+
+import styles from "./AdditionVisualizer.module.css";
+
+function parseOperand(value: string): number {
+  if (value.trim() === "") {
+    return 0;
+  }
+
+  return Number(value);
+}
+
+export function AdditionVisualizer() {
+  const firstId = useId();
+  const secondId = useId();
+  const [firstValue, setFirstValue] = useState("0");
+  const [secondValue, setSecondValue] = useState("0");
+
+  const left = parseOperand(firstValue);
+  const right = parseOperand(secondValue);
+  const result = add(left, right);
+
+  return (
+    <section className={styles.shell}>
+      <div className={styles.card}>
+        <p className={styles.eyebrow}>Workspace plumbing demo</p>
+        <h1 className={styles.title}>Add Two Numbers</h1>
+        <p className={styles.copy}>
+          The inputs live in the Next.js app, and the math comes from the shared
+          workspace library.
+        </p>
+
+        <div className={styles.formGrid}>
+          <label className={styles.field} htmlFor={firstId}>
+            <span>First number</span>
+            <input
+              id={firstId}
+              inputMode="decimal"
+              name="firstNumber"
+              onChange={(event) => setFirstValue(event.target.value)}
+              type="number"
+              value={firstValue}
+            />
+          </label>
+
+          <label className={styles.field} htmlFor={secondId}>
+            <span>Second number</span>
+            <input
+              id={secondId}
+              inputMode="decimal"
+              name="secondNumber"
+              onChange={(event) => setSecondValue(event.target.value)}
+              type="number"
+              value={secondValue}
+            />
+          </label>
+        </div>
+
+        <div aria-label="Addition summary" className={styles.visualizer}>
+          <article className={styles.statCard}>
+            <span className={styles.statLabel}>First</span>
+            <strong>{left}</strong>
+          </article>
+          <article className={styles.statCard}>
+            <span className={styles.statLabel}>Second</span>
+            <strong>{right}</strong>
+          </article>
+          <article className={styles.resultCard}>
+            <span className={styles.statLabel}>Result</span>
+            <strong data-testid="result-value">{result}</strong>
+          </article>
+        </div>
+      </div>
+    </section>
+  );
+}
+
*** Add File: apps/web/src/components/AdditionVisualizer.module.css
+.shell {
+  display: grid;
+  min-height: 100vh;
+  padding: 2rem;
+  place-items: center;
+}
+
+.card {
+  width: min(100%, 48rem);
+  padding: 2rem;
+  border: 1px solid #d9e0ea;
+  border-radius: 1.5rem;
+  background: linear-gradient(180deg, #ffffff 0%, #edf4ff 100%);
+  box-shadow: 0 1.5rem 4rem rgba(22, 32, 51, 0.12);
+}
+
+.eyebrow {
+  margin: 0;
+  color: #4f6b95;
+  font-size: 0.875rem;
+  font-weight: 700;
+  letter-spacing: 0.08em;
+  text-transform: uppercase;
+}
+
+.title {
+  margin: 0.75rem 0 0;
+  font-size: clamp(2rem, 3vw, 3rem);
+}
+
+.copy {
+  margin: 1rem 0 0;
+  max-width: 42rem;
+  color: #44516a;
+  line-height: 1.6;
+}
+
+.formGrid {
+  display: grid;
+  gap: 1rem;
+  margin-top: 1.75rem;
+}
+
+.field {
+  display: grid;
+  gap: 0.5rem;
+  font-weight: 600;
+}
+
+.field input {
+  width: 100%;
+  padding: 0.875rem 1rem;
+  border: 1px solid #bfd0e4;
+  border-radius: 0.9rem;
+  background: #ffffff;
+}
+
+.visualizer {
+  display: grid;
+  gap: 1rem;
+  margin-top: 1.75rem;
+}
+
+.statCard,
+.resultCard {
+  display: grid;
+  gap: 0.35rem;
+  padding: 1.25rem;
+  border-radius: 1rem;
+  background: rgba(255, 255, 255, 0.92);
+}
+
+.statCard strong,
+.resultCard strong {
+  font-size: clamp(1.75rem, 4vw, 2.5rem);
+}
+
+.resultCard {
+  background: #162033;
+  color: #f8fbff;
+}
+
+.statLabel {
+  font-size: 0.9rem;
+  font-weight: 700;
+  letter-spacing: 0.04em;
+  text-transform: uppercase;
+}
+
+@media (min-width: 48rem) {
+  .formGrid,
+  .visualizer {
+    grid-template-columns: repeat(2, minmax(0, 1fr));
+  }
+
+  .resultCard {
+    grid-column: 1 / -1;
+  }
+}
+
*** Add File: apps/web/src/components/AdditionVisualizer.test.tsx
+import { fireEvent, render, screen } from "@testing-library/react";
+import { describe, expect, test } from "vitest";
+
+import { AdditionVisualizer } from "./AdditionVisualizer";
+
+describe("AdditionVisualizer", () => {
+  test("updates the result when either operand changes", () => {
+    render(<AdditionVisualizer />);
+
+    fireEvent.change(screen.getByLabelText("First number"), {
+      target: { value: "20" }
+    });
+    fireEvent.change(screen.getByLabelText("Second number"), {
+      target: { value: "22" }
+    });
+
+    expect(screen.getByTestId("result-value").textContent).toBe("42");
+  });
+});
+
*** Add File: apps/web/tests/e2e/addition.spec.ts
+import { expect, test } from "@playwright/test";
+
+test("shows the addition visualizer and updates the result live", async ({
+  page
+}) => {
+  await page.goto("/");
+
+  await expect(
+    page.getByRole("heading", { name: "Add Two Numbers" })
+  ).toBeVisible();
+
+  await page.getByLabel("First number").fill("20");
+  await page.getByLabel("Second number").fill("22");
+
+  await expect(page.getByTestId("result-value")).toHaveText("42");
+});
